#include<stdio.h>
#include<string.h>
int main()
{
int i,j=0,l;
char a[200];
char c[200];
scanf("%s",&a);
l=strlen(a);
for(i=0;i<l;i++)
{
if(a[i]=='W' && a[i+1]=='U' && a[i+2]=='B')
{
if(j!=0)
{
c[j]=' ';
j=j+1;
}
i=i+2;
}
else
{
c[j]=a[i];
j=j+1;
}
}
c[j]='\0';
printf("%s",c);
return 0;
}

